mapper.sql:
SELECT COUNT(1) OVER() AS TOTAL_CNT , ROW_NUMBER() OVER (ORDER BY A.ACTV_DTTM DESC, A.USER_ACTV_ID DESC) LINE_NO , A.USER_ACTV_ID , A.ACTV_DTTM , A.CNTN_IP , A.USER_TYCD , A.USER_REQ_MENU , A.USER_REQ_CTS , U.USER_ID , U.USER_RPRS_ID , U.USERNM , U.STDNT_NO , S.SBJCT_ID , S.SBJCTNM , S.SBJCT_YR , S.SBJCT_SMSTR , S.DVCLAS_NO , D.DEPTNM AS DEPT_NM , O.ORGNM FROM TB_LMS_LOG_USER_ACTV A INNER JOIN TB_LMS_USER U ON U.USER_ID = A.USER_ID INNER JOIN TB_LMS_SBJCT S ON S.SBJCT_ID = A.SBJCT_ID LEFT JOIN TB_LMS_DEPT D ON D.DEPT_ID = S.DEPT_ID INNER JOIN TB_LMS_ORG O ON O.ORG_ID = U.ORG_ID WHERE A.SBJCT_ID = #{sbjctId}
AND A.ACTV_DTTM >= #{searchFrom} AND A.ACTV_DTTM <= #{searchTo}
AND A.USER_TYCD IN ('PROF', 'COPROF')
AND A.USER_TYCD = #{userTycd}
AND A.USER_ID IN ( SELECT USER_ID FROM TB_LMS_USER WHERE USER_RPRS_ID = #{searchText} OR STDNT_NO = #{searchText} OR USERNM LIKE '%' || #{searchText} || '%' )
ORDER BY A.ACTV_DTTM DESC, A.USER_ACTV_ID DESC
